import React, { useState, useEffect, useRef } from "react";

// 최대 동시 파일 전송 개수
const MAX_CONCURRENT_FILES = 30;

interface User {
  id: string;
  nickname: string;
  sessionId?: string; // 서버에서 init 메시지로 할당됨
  isOnline?: boolean;
}

interface SystemMessage {
  id: number;
  message: string;
  timestamp: string;
}

const App: React.FC = () => {
  // 상태 변수들
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [users, setUsers] = useState<User[]>([]);
  const [systemMessages, setSystemMessages] = useState<SystemMessage[]>([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [showTransferModal, setShowTransferModal] = useState(false);
  const [showWifiAlert, setShowWifiAlert] = useState(false);
  const [selectedFiles, setSelectedFiles] = useState<File[]>([]);
  const [selectedUser, setSelectedUser] = useState<User | null>(null);
  const [showContextMenu, setShowContextMenu] = useState<{ x: number; y: number } | null>(null);
  const [showProfileModal, setShowProfileModal] = useState(false);
  const [showMessagesArea, setShowMessagesArea] = useState(true);
  const [modal, setModal] = useState({ visible: false, message: "" });

  const fileInputRef = useRef<HTMLInputElement>(null);
  const ws = useRef<WebSocket | null>(null);

  // 검색어에 따라 사용자 목록 필터링
  const filteredUsers = users.filter((user) =>
    user.nickname.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // 시스템 메시지 추가 함수
  const addSystemMessage = (message: string) => {
    const newMessage: SystemMessage = {
      id: systemMessages.length + 1,
      message,
      timestamp: new Date().toLocaleTimeString(),
    };
    setSystemMessages((prev) => [...prev, newMessage]);
  };

  // UUID 생성 함수 (RFC4122 v4)
  const generateUUID = (): string => {
    return "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx".replace(/[xy]/g, (c) => {
      const r = (Math.random() * 16) | 0;
      const v = c === "x" ? r : ((r & 0x3) | 0x8);
      return v.toString(16);
    });
  };

  // 송신자가 사용자를 클릭하면 파일 전송 요청을 보냄
  const handleUserClick = (user: User) => {
    setSelectedUser(user);
    if (ws.current && currentUser) {
      // 파일 전송 요청 메시지 전송 (송신자 → 수신자)
      ws.current.send(
        JSON.stringify({
          type: "request",
          senderSessionId: currentUser.sessionId,
          senderNickname: currentUser.nickname,
          target: user.sessionId,
        })
      );
      addSystemMessage("파일 전송 요청을 보냈습니다.");
    }
  };

  // WebSocket 연결 설정
  useEffect(() => {
    ws.current = new WebSocket("ws://localhost:8080/ws");

    ws.current.onopen = () => {
      addSystemMessage("서버에 연결되었습니다.");
      setModal({ visible: false, message: "" });
    };

    ws.current.onmessage = (event) => {
      if (typeof event.data === "string") {
        console.log("서버로부터 문자열 메시지:", event.data);
        // 네트워크 오류 메시지 체크
        if (event.data.indexOf("상대방과 같은 서브넷에 있지 않아 전송할 수 없습니다") !== -1) {
          setModal({
            visible: true,
            message: "같은 wifi에 연결되어 있지 않아요. 같은 wifi에 접속해주세요.",
          });
          return;
        }
        try {
          const data = JSON.parse(event.data);
          switch (data.type) {
            case "init":
              setCurrentUser({
                id: data.sessionId,
                nickname: data.nickname,
                sessionId: data.sessionId,
                isOnline: true,
              });
              addSystemMessage(`내 정보: ${data.nickname} (${data.sessionId})`);
              break;
            case "userList":
              setUsers(data.users);
              break;
            case "request":
              // 수신자가 파일 전송 요청을 받으면 모달을 띄움
              setSelectedUser({
                id: data.senderSessionId,
                nickname: data.senderNickname,
                sessionId: data.senderSessionId,
              });
              setShowTransferModal(true);
              addSystemMessage(`${data.senderNickname}님이 파일 전송을 요청했습니다.`);
              break;
            case "response":
              {data.data.accepted ? (
                <>
                  {addSystemMessage("상대방이 전송 요청을 수락하였습니다. 파일을 전송해주세요.")}
                  {/* 사용자에게 직접 클릭하도록 버튼 제공 */}
                  <button onClick={() => fileInputRef.current && fileInputRef.current.click()}>
                    파일 선택하기
                  </button>
                </>
              ) : (
                addSystemMessage("상대방이 전송 요청을 거절하였습니다.")
              )}
              break;
            default:
              addSystemMessage("서버 메시지: " + event.data);
          }
        } catch (error) {
          addSystemMessage("서버: " + event.data);
        }
      } else {
        console.log("서버로부터 바이너리 메시지 수신");
        // 바이너리 메시지: 파일 다운로드 처리
        const blob = event.data instanceof Blob ? event.data : new Blob([event.data]);
        const url = URL.createObjectURL(blob);
        const a = document.createElement("a");
        a.style.display = "none";
        a.href = url;
        a.download = "Netdrops_download.jpg";
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
        addSystemMessage("이미지 파일이 다운로드되었습니다.");
      }
    };

    ws.current.onerror = (error) => {
      addSystemMessage("WebSocket 에러 발생");
    };

    ws.current.onclose = () => {
      addSystemMessage("연결이 종료되었습니다.");
    };

    return () => {
      if (ws.current) ws.current.close();
    };
  }, []);

  // 파일 전송 핸들러 (송신자가 파일을 선택한 후)
  const handleSendFiles = () => {
    if (selectedFiles.length > 0 && selectedUser) {
      addSystemMessage(`Sending ${selectedFiles.length} files to ${selectedUser.nickname}...`);
      const isInSameSubnet = Math.random() >= 0.25; // 예시: 75% 확률
      if (!isInSameSubnet) {
        addSystemMessage("상대방과 같은 서브넷에 있지 않아 전송할 수 없습니다.");
        setShowWifiAlert(true);
        setModal({
          visible: true,
          message: "같은 wifi에 연결되어 있지 않아요. 같은 wifi에 접속해주세요.",
        });
        return;
      }
      selectedFiles.forEach((file) => {
        const fileId = generateUUID();
        if (ws.current) {
          ws.current.send(
            JSON.stringify({ type: "meta", fileId: fileId, target: selectedUser.sessionId })
          );
        }
        addSystemMessage(`파일 메타 정보 전송됨: ${file.name} (fileId: ${fileId})`);
        const reader = new FileReader();
        reader.onload = (ev) => {
          const arrayBuffer = ev.target?.result;
          if (arrayBuffer instanceof ArrayBuffer) {
            const encoder = new TextEncoder();
            const header = encoder.encode(fileId);
            const combined = new Uint8Array(header.length + arrayBuffer.byteLength);
            combined.set(header, 0);
            combined.set(new Uint8Array(arrayBuffer), header.length);
            if (ws.current) ws.current.send(combined.buffer);
            addSystemMessage(`사진 전송됨: ${file.name}`);
          }
        };
        reader.readAsArrayBuffer(file);
      });
      setSelectedFiles([]);
      setSelectedUser(null);
      setShowTransferModal(false);
    }
  };

  // 파일 선택 핸들러 (송신자가 파일을 선택할 때)
  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const filesArray = Array.from(e.target.files);
      if (filesArray.length > MAX_CONCURRENT_FILES) {
        addSystemMessage("You can only select up to 30 files at once.");
        return;
      }
      setSelectedFiles(filesArray);
    }
  };

  // 수신자가 Transfer Request Modal에서 응답할 때 (수신자 역할)
  const handleTransferResponse = (accepted: boolean) => {
    // 수신자 클라이언트가 응답 메시지를 송신자에게 전송
    if (ws.current && selectedUser) {
      ws.current.send(
        JSON.stringify({
          type: "response",
          data: { accepted },
          target: selectedUser.sessionId,
        })
      );
    }
    setShowTransferModal(false);
    setSelectedUser(null);
  };

  // 검색 초기화
  const clearSearch = () => {
    setSearchTerm("");
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col">
      {/* Header: 현재 사용자 정보 표시 */}
      <header className="bg-white shadow-sm py-6 px-4">
        <div className="max-w-5xl mx-auto text-center">
          <h1 className="text-2xl font-bold text-[#007AFF]">Netdrops</h1>
          {currentUser && (
            <>
              <div className="mt-2 text-lg font-semibold">{currentUser.nickname}</div>
              <div className="text-sm text-gray-500">Session ID: {currentUser.sessionId}</div>
              <div className="mt-2 flex items-center justify-center">
                <span
                  className={`inline-block w-2 h-2 rounded-full mr-2 ${
                    currentUser.isOnline ? "bg-green-500" : "bg-red-500"
                  }`}
                ></span>
                <span className="text-sm">
                  {currentUser.isOnline ? "Online" : "Offline"}
                </span>
              </div>
            </>
          )}
        </div>
      </header>

      {/* System Messages Area */}
      <div className="max-w-5xl mx-auto w-full px-4 mt-4">
        <div className="flex items-center justify-between mb-2">
          <h2 className="text-md font-medium text-gray-700">System Messages</h2>
          <button
            onClick={() => setShowMessagesArea(!showMessagesArea)}
            className="text-sm text-[#007AFF] cursor-pointer rounded whitespace-nowrap"
          >
            {showMessagesArea ? "Hide" : "Show"}
          </button>
        </div>
        {showMessagesArea && (
          <div className="bg-gray-100 rounded-lg p-3 max-h-40 overflow-y-auto mb-4">
            {systemMessages.map((msg) => (
              <div key={msg.id} className="mb-2 last:mb-0">
                <span className="text-xs text-gray-500">{msg.timestamp}</span>
                <p className="text-sm">{msg.message}</p>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Search Box */}
      <div className="max-w-md mx-auto w-full px-4 mt-2 mb-6">
        <div className="relative">
          <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
            <i className="fas fa-search text-gray-400"></i>
          </div>
          <input
            type="text"
            className="block w-full pl-10 pr-10 py-2 border border-gray-300 rounded-full focus:ring-[#007AFF] focus:border-[#007AFF] text-sm"
            placeholder="Search by nickname"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
          {searchTerm && (
            <button
              className="absolute inset-y-0 right-0 pr-3 flex items-center cursor-pointer rounded whitespace-nowrap"
              onClick={clearSearch}
            >
              <i className="fas fa-times text-gray-400"></i>
            </button>
          )}
        </div>
      </div>

      {/* User Grid */}
      <div className="flex-grow max-w-5xl mx-auto w-full px-4 mb-8">
        <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6 gap-4">
          {filteredUsers.length === 0
            ? "No users connected."
            : filteredUsers
                .filter((user) => user.sessionId !== currentUser?.sessionId)
                .map((user) => (
                  <div
                    key={user.id}
                    className="bg-white rounded-lg p-4 shadow-sm hover:shadow-md transition-shadow duration-200 text-center cursor-pointer transform hover:-translate-y-1 transition-transform"
                    onClick={() => handleUserClick(user)}
                    onContextMenu={(e) => {
                      e.preventDefault();
                      setSelectedUser(user);
                      setShowContextMenu({ x: e.clientX, y: e.clientY });
                    }}
                  >
                    <div className="w-16 h-16 mx-auto bg-[#007AFF] rounded-full flex items-center justify-center text-white text-xl font-bold mb-2">
                      {user.nickname.charAt(0).toUpperCase()}
                    </div>
                    <div className="text-sm font-medium truncate">{user.nickname}</div>
                  </div>
                ))}
        </div>
      </div>

      {/* Hidden File Input */}
      <input
        type="file"
        ref={fileInputRef}
        className="hidden"
        multiple
        onChange={handleFileSelect}
        accept="image/*"
      />

      {/* File Transfer UI (송신자 파일 선택 후 미리보기 및 전송) */}
      {selectedFiles.length > 0 && selectedUser && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-20">
          <div className="bg-white rounded-lg p-6 max-w-xl w-full mx-4">
            <h3 className="text-lg font-semibold mb-4">
              Send files to {selectedUser.nickname}
            </h3>
            <div className="border-2 border-dashed border-gray-300 rounded-lg p-4 mb-4">
              <div className="text-sm mb-2">
                Selected {selectedFiles.length}{" "}
                {selectedFiles.length === 1 ? "file" : "files"} (max 30)
              </div>
              <div className="flex overflow-x-auto pb-2 gap-2">
                {selectedFiles.map((file, index) => (
                  <div
                    key={index}
                    className="flex-shrink-0 w-16 h-16 bg-gray-100 rounded overflow-hidden"
                  >
                    <img
                      src={URL.createObjectURL(file)}
                      alt={`Preview ${index}`}
                      className="w-full h-full object-cover"
                    />
                  </div>
                ))}
              </div>
            </div>
            <div className="flex justify-end gap-3">
              <button
                onClick={() => {
                  setSelectedFiles([]);
                  setSelectedUser(null);
                }}
                className="px-4 py-2 border border-gray-300 rounded-md text-gray-700 hover:bg-gray-50 whitespace-nowrap"
              >
                Cancel
              </button>
              <button
                onClick={handleSendFiles}
                className="px-4 py-2 bg-[#007AFF] text-white rounded-md hover:bg-blue-600 whitespace-nowrap"
              >
                Send Photos
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Transfer Request Modal (수신자 측: 파일 전송 요청에 대한 응답) */}
      {showTransferModal && selectedUser && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-20">
          <div className="bg-white rounded-lg p-6 max-w-md w-full mx-4 shadow-xl">
            <div className="text-center mb-4">
              <div className="w-16 h-16 mx-auto bg-[#007AFF] rounded-full flex items-center justify-center text-white text-xl font-bold mb-3">
                {selectedUser.nickname.charAt(0).toUpperCase()}
              </div>
              <h3 className="text-lg font-semibold">File Transfer Request</h3>
              <p className="text-gray-600 mt-1">
                {selectedUser.nickname} wants to share files with you
              </p>
            </div>
            <div className="flex justify-center gap-3 mt-6">
              <button
                onClick={() => handleTransferResponse(false)}
                className="px-5 py-2 border border-gray-300 rounded-md text-gray-700 hover:bg-gray-50 whitespace-nowrap"
              >
                Decline
              </button>
              <button
                onClick={() => handleTransferResponse(true)}
                className="px-5 py-2 bg-[#007AFF] text-white rounded-md hover:bg-blue-600 whitespace-nowrap"
              >
                Accept
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Context Menu */}
      {showContextMenu && selectedUser && (
        <div
          className="fixed bg-white rounded-lg shadow-xl py-2 z-30"
          style={{
            top: showContextMenu.y,
            left: showContextMenu.x,
            transform: "translate(-50%, -50%)",
          }}
        >
          <button
            className="w-full px-4 py-2 text-left hover:bg-gray-100 text-sm rounded whitespace-nowrap"
            onClick={() => {
              if (fileInputRef.current) {
                fileInputRef.current.click();
              }
              setShowContextMenu(null);
            }}
          >
            <i className="fas fa-file-upload mr-2"></i>Send Files
          </button>
          <button
            className="w-full px-4 py-2 text-left hover:bg-gray-100 text-sm rounded whitespace-nowrap"
            onClick={() => {
              setShowProfileModal(true);
              setShowContextMenu(null);
            }}
          >
            <i className="fas fa-user mr-2"></i>View Profile
          </button>
        </div>
      )}

      {/* Profile Modal */}
      {showProfileModal && selectedUser && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-20">
          <div className="bg-white rounded-lg p-6 max-w-md w-full mx-4 shadow-xl">
            <div className="text-center mb-6">
              <div className="w-24 h-24 mx-auto bg-[#007AFF] rounded-full flex items-center justify-center text-white text-3xl font-bold mb-4">
                {selectedUser.nickname.charAt(0).toUpperCase()}
              </div>
              <h3 className="text-xl font-semibold">{selectedUser.nickname}</h3>
              <p className="text-gray-600 mt-2">User ID: {selectedUser.id}</p>
              <div className="mt-4 text-sm text-gray-500">
                <p>Last seen: Just now</p>
                <p>Status: Online</p>
                <p>Files shared: 142</p>
              </div>
            </div>
            <div className="flex justify-center gap-3">
              <button
                onClick={() => {
                  if (fileInputRef.current) {
                    fileInputRef.current.click();
                  }
                  setShowProfileModal(false);
                }}
                className="px-4 py-2 bg-[#007AFF] text-white rounded-md hover:bg-blue-600 whitespace-nowrap"
              >
                Send Files
              </button>
              <button
                onClick={() => setShowProfileModal(false)}
                className="px-4 py-2 border border-gray-300 rounded-md text-gray-700 hover:bg-gray-50 whitespace-nowrap"
              >
                Close
              </button>
            </div>
          </div>
        </div>
      )}

      {/* WiFi Alert Modal */}
      {showWifiAlert && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-20">
          <div className="bg-white rounded-lg p-6 max-w-md w-full mx-4 shadow-xl">
            <div className="text-center mb-4">
              <div className="w-16 h-16 mx-auto bg-yellow-500 rounded-full flex items-center justify-center text-white text-xl font-bold mb-3">
                <i className="fas fa-wifi"></i>
              </div>
              <h3 className="text-lg font-semibold">네트워크 연결 오류</h3>
              <p className="text-gray-600 mt-2">
                같은 wifi에 연결되어 있지 않아요. 같은 wifi에 접속해주세요.
              </p>
            </div>
            <div className="flex justify-center mt-6">
              <button
                onClick={() => {
                  setShowWifiAlert(false);
                  setSelectedFiles([]);
                  setSelectedUser(null);
                }}
                className="px-5 py-2 bg-[#007AFF] text-white rounded-md hover:bg-blue-600 whitespace-nowrap"
              >
                확인
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;
